// ═══════════════════════════════════════════════════════════
// Object State Machine Engine
// ═══════════════════════════════════════════════════════════
//
// Objects are defined as JSON with state machines. Each state can have:
//   - visual: string descriptor for renderer
//   - particles: optional particle effect name
//   - emoji: optional emoji to float on enter
//   - auto_next: { state, after (seconds) } — timed auto-transition
//   - transitions: { action_name: { next, duration?, requires?, produces?, target? } }
//
// The engine ticks all objects, advancing auto_next timers.
// Characters trigger transitions via interact(objectId, action).

export class ObjectInstance {
  constructor(def) {
    this.id = def.id;
    this.name = def.name;
    this.sector = def.sector;
    this.arena = def.arena;
    this.position = { ...def.position };
    this.states = def.states;
    this.state = def.state || Object.keys(def.states)[0];
    this.timer = 0; // ms elapsed in current state
    this.autoNextDuration = this._getAutoNextDuration(); // ms until auto-transition (null if none)
  }

  _getAutoNextDuration() {
    const stateDef = this.states[this.state];
    if (stateDef?.auto_next) {
      return stateDef.auto_next.after * 1000; // convert seconds → ms
    }
    return null;
  }

  get currentStateDef() {
    return this.states[this.state];
  }

  get visual() {
    return this.currentStateDef?.visual || this.state;
  }

  get particles() {
    return this.currentStateDef?.particles || null;
  }

  get timeRemainingMs() {
    if (this.autoNextDuration === null) return null;
    return Math.max(0, this.autoNextDuration - this.timer);
  }

  // Returns a transition event if auto_next fires, or null
  tick(deltaMs) {
    if (this.autoNextDuration === null) return null;

    this.timer += deltaMs;

    if (this.timer >= this.autoNextDuration) {
      const autoNext = this.currentStateDef.auto_next;
      return this._transition(autoNext.state, 'auto');
    }

    return null;
  }

  // Attempt a character-triggered interaction.
  // Returns a transition event, or null if no valid transition.
  interact(action = 'use') {
    const stateDef = this.currentStateDef;
    if (!stateDef?.transitions) return null;

    const transition = stateDef.transitions[action];
    if (!transition) return null;

    // If the transition requires a character, that's expected (caller is a character)
    return this._transition(transition.next, action, transition);
  }

  _transition(nextState, trigger, transitionDef = null) {
    const prevState = this.state;
    const prevVisual = this.visual;

    this.state = nextState;
    this.timer = 0;
    this.autoNextDuration = this._getAutoNextDuration();

    return {
      objectId: this.id,
      objectName: this.name,
      from: prevState,
      to: nextState,
      trigger,
      visual: this.visual,
      particles: this.particles,
      emoji: this.currentStateDef?.emoji || null,
      produces: transitionDef?.produces || null,
      target: transitionDef?.target || null,
      timestamp: Date.now(),
    };
  }

  // Force-set state (e.g., when another object's transition produces something here)
  setState(newState) {
    if (!this.states[newState]) return null;
    return this._transition(newState, 'external');
  }

  toJSON() {
    return {
      id: this.id,
      name: this.name,
      state: this.state,
      visual: this.visual,
      particles: this.particles,
      timer: this.timer,
      timeRemainingMs: this.timeRemainingMs,
      sector: this.sector,
      arena: this.arena,
      position: this.position,
    };
  }
}

export class ObjectEngine {
  constructor() {
    this.objects = new Map();    // id → ObjectInstance
    this.listeners = [];         // event subscribers
  }

  addObject(def) {
    const obj = new ObjectInstance(def);
    this.objects.set(obj.id, obj);
    return obj;
  }

  addObjects(defs) {
    for (const def of defs) {
      this.addObject(def);
    }
  }

  get(objectId) {
    return this.objects.get(objectId);
  }

  getAll() {
    return [...this.objects.values()];
  }

  getBySector(sector) {
    return this.getAll().filter(o => o.sector === sector);
  }

  // Advance all object timers by deltaMs.
  // Returns array of transition events that fired.
  tick(deltaMs) {
    const events = [];

    for (const obj of this.objects.values()) {
      const event = obj.tick(deltaMs);
      if (event) {
        events.push(event);
        this._handleProduction(event);
      }
    }

    // Notify listeners
    for (const event of events) {
      this._emit(event);
    }

    return events;
  }

  // Character interacts with an object.
  // Returns transition event or null.
  interact(objectId, action = 'use') {
    const obj = this.objects.get(objectId);
    if (!obj) return null;

    const event = obj.interact(action);
    if (event) {
      this._handleProduction(event);
      this._emit(event);
    }

    return event;
  }

  // Handle "produces" side-effects (e.g., oven done → bread in display_case)
  _handleProduction(event) {
    if (event.produces && event.target) {
      const targetObj = this.objects.get(event.target);
      if (targetObj) {
        // Map production to a state on the target object
        const targetEvent = targetObj.setState(event.produces);
        if (targetEvent) {
          targetEvent.trigger = `produced_by:${event.objectId}`;
          this._emit(targetEvent);
        }
      }
    }
  }

  onTransition(callback) {
    this.listeners.push(callback);
    return () => {
      this.listeners = this.listeners.filter(l => l !== callback);
    };
  }

  _emit(event) {
    for (const listener of this.listeners) {
      listener(event);
    }
  }

  // Snapshot of all objects for debugging/display
  snapshot() {
    const result = {};
    for (const [id, obj] of this.objects) {
      result[id] = obj.toJSON();
    }
    return result;
  }
}

