// ── Object ID → interaction particle type ──
function getInteractParticleType(char) {
  const id = char.targetObjectId;
  if (!id) return 'interact_sparkle';
  if (id.includes('espresso') || id.includes('coffee')) return 'steam';
  if (id.includes('stove')) return 'oven_embers';
  if (id.includes('sink')) return 'water_drops';
  if (id.includes('easel')) return 'paint_splatter';
  if (id.includes('book')) return 'paper_flutter';
  return 'interact_sparkle';
}

// ── Sprite preloader ──
function loadImage(src) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error(`Failed to load: ${src}`));
    img.src = src;
  });
}

/**
 * Preload all tile, object, and character sprites.
 * Returns { tiles: Map, objects: Map, characters: Map }
 * Failed loads are silently skipped (renderer falls back to colored rects).
 */
export async function preloadSprites() {
  const tiles = new Map();
  const objects = new Map();
  const characters = new Map();
  const props = new Map();

  const promises = [];

  // Tile sprites
  for (const [tileId, path] of Object.entries(TILE_SPRITES)) {
    promises.push(
      loadImage(path)
        .then(img => tiles.set(Number(tileId), img))
        .catch(() => { /* fallback to color */ })
    );
  }

  // Object sprites
  for (const [visual, path] of Object.entries(OBJECT_SPRITE_PATHS)) {
    promises.push(
      loadImage(path)
        .then(img => objects.set(visual, img))
        .catch(() => { /* fallback to color */ })
    );
  }

  // Character sprites
  for (const [key, path] of Object.entries(CHARACTER_SPRITE_PATHS)) {
    promises.push(
      loadImage(path)
        .then(img => characters.set(key, img))
        .catch(() => { /* fallback to color */ })
    );
  }

  // Prop sprites
  for (const [key, path] of Object.entries(PROP_SPRITES)) {
    promises.push(
      loadImage(path)
        .then(img => props.set(key, img))
        .catch(() => { /* fallback — props just won't render */ })
    );
  }

  await Promise.all(promises);
  return { tiles, objects, characters, props };
}

export class Renderer {
  constructor(container) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = MAP_W;
    this.canvas.height = MAP_H;
    this.ctx = this.canvas.getContext('2d');
    this.ctx.imageSmoothingEnabled = false;

    // CSS scaling — fill window, keep aspect ratio
    this.canvas.style.display = 'block';
    this.canvas.style.imageRendering = 'pixelated';

    // High-res text overlay canvas (renders at display resolution for crisp text)
    this.textCanvas = document.createElement('canvas');
    this.textCanvas.style.position = 'absolute';
    this.textCanvas.style.top = '0';
    this.textCanvas.style.left = '0';
    this.textCanvas.style.pointerEvents = 'none';
    this.textCtx = this.textCanvas.getContext('2d');

    this._resize();
    window.addEventListener('resize', () => this._resize());

    container.appendChild(this.canvas);
    container.appendChild(this.textCanvas);

    // Sprite caches (populated by setSprites)
    this.tileSprites = null;      // Map<tileId, Image>
    this.objectSprites = null;    // Map<visualKey, Image>
    this.characterSprites = null; // Map<spriteKey, Image>

    // Pre-rendered tilemap (offscreen canvas, re-drawn only when sprites load)
    this._tilemapCache = null;

    // Particle state
    this.particles = [];

    // Emoji float state
    this.emojiFloats = [];

    // Speech bubble state
    this.speechBubbles = [];

    // Status bar text
    this.statusText = '';

    // Stars (lazy-initialized on first night render)
    this._stars = null;

    // Ambient particles (fireflies, leaves)
    this._ambientParticles = [];
    this._leafTimer = 0;
    this._waterTiles = null;
    this._windowTiles = null;
    this._lanternPositions = null;

    // Animation
    this._rafId = null;
    this._lastTime = 0;
    this._renderCallback = null;
  }

  /** Assign preloaded sprites and bake the tilemap cache. */
  setSprites(sprites) {
    this.tileSprites = sprites.tiles;
    this.objectSprites = sprites.objects;
    this.characterSprites = sprites.characters;
    this.propSprites = sprites.props || null;
    this._bakeTilemapCache();
  }

  /** Pre-render tilemap to an offscreen canvas for fast blitting. */
  _bakeTilemapCache() {
    const offscreen = document.createElement('canvas');
    offscreen.width = MAP_W;
    offscreen.height = MAP_H;
    const octx = offscreen.getContext('2d');
    octx.imageSmoothingEnabled = false;

    // Fill with base grass color so no transparency bleeds through
    octx.fillStyle = '#d4c5a9'; // café tile floor base
    octx.fillRect(0, 0, MAP_W, MAP_H);

    for (let row = 0; row < MAP_ROWS; row++) {
      for (let col = 0; col < MAP_COLS; col++) {
        const tile = MAP[row][col];
        const x = col * TILE_SIZE;
        const y = row * TILE_SIZE;

        const sprite = this.tileSprites && this.tileSprites.get(tile);
        if (sprite) {
          octx.drawImage(sprite, x, y, TILE_SIZE, TILE_SIZE);
        } else {
          octx.fillStyle = TILE_COLORS[tile] || '#ff00ff';
          octx.fillRect(x, y, TILE_SIZE, TILE_SIZE);
        }
      }
    }

    // Bake decorative props on top of tiles (static, never change)
    for (const prop of PROPS) {
      const sprite = this.propSprites && this.propSprites.get(prop.type);
      if (sprite) {
        const pw = (prop.tw || 1) * TILE_SIZE;
        const ph = (prop.th || 1) * TILE_SIZE;
        octx.drawImage(sprite, prop.tx * TILE_SIZE, prop.ty * TILE_SIZE, pw, ph);
      }
    }

    this._tilemapCache = offscreen;
  }

  _resize() {
    const aspect = MAP_W / MAP_H;
    const winW = window.innerWidth;
    const winH = window.innerHeight;
    const winAspect = winW / winH;

    let cssW, cssH;
    if (winAspect > aspect) {
      cssH = winH;
      cssW = winH * aspect;
    } else {
      cssW = winW;
      cssH = winW / aspect;
    }

    this.canvas.style.width = cssW + 'px';
    this.canvas.style.height = cssH + 'px';
    this.canvas.style.margin = 'auto';

    this.cssScale = cssW / MAP_W;
    this.cssOffsetX = (winW - cssW) / 2;
    this.cssOffsetY = (winH - cssH) / 2;

    // Resize text overlay to match display resolution
    if (this.textCanvas) {
      const dpr = window.devicePixelRatio || 1;
      this.textCanvas.style.width = cssW + 'px';
      this.textCanvas.style.height = cssH + 'px';
      this.textCanvas.width = Math.round(cssW * dpr);
      this.textCanvas.height = Math.round(cssH * dpr);
      this.textScale = this.textCanvas.width / MAP_W;
    }
  }

  // Convert page click coords to tile coords
  pageToTile(pageX, pageY) {
    const rect = this.canvas.getBoundingClientRect();
    const canvasX = (pageX - rect.left) / this.cssScale;
    const canvasY = (pageY - rect.top) / this.cssScale;
    return {
      tx: Math.floor(canvasX / TILE_SIZE),
      ty: Math.floor(canvasY / TILE_SIZE),
      px: canvasX,
      py: canvasY,
    };
  }

  // ── Tilemap ──
  renderTilemap() {
    if (this._tilemapCache) {
      this.ctx.drawImage(this._tilemapCache, 0, 0);
    } else {
      // Fallback: draw colored rectangles (no sprites loaded yet)
      const ctx = this.ctx;
      for (let row = 0; row < MAP_ROWS; row++) {
        for (let col = 0; col < MAP_COLS; col++) {
          const tile = MAP[row][col];
          ctx.fillStyle = TILE_COLORS[tile] || '#ff00ff';
          ctx.fillRect(col * TILE_SIZE, row * TILE_SIZE, TILE_SIZE, TILE_SIZE);
        }
      }
    }
  }

  // ── Objects ──
  renderObjects(objects) {
    const ctx = this.ctx;

    for (const obj of objects) {
      const tx = obj.position.tx;
      const ty = obj.position.ty;
      const pxX = tx * TILE_SIZE;
      const pxY = ty * TILE_SIZE;
      const w = (obj.position.tw || 1) * TILE_SIZE;
      const h = (obj.position.th || 1) * TILE_SIZE;

      const sprite = this.objectSprites && this.objectSprites.get(obj.visual);

      if (sprite) {
        // Draw sprite scaled to object tile size
        ctx.drawImage(sprite, pxX, pxY, w, h);
      } else {
        // Fallback: colored rectangle
        const color = OBJECT_COLORS[obj.visual] || DEFAULT_OBJ_COLOR;
        ctx.fillStyle = color;
        ctx.fillRect(pxX + 1, pxY + 1, w - 2, h - 2);
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 1;
        ctx.strokeRect(pxX + 0.5, pxY + 0.5, w - 1, h - 1);
      }

      // Oven flash on interaction (bright overlay for first 200ms)
      if (this._activeInteractions?.has(obj.id) && (obj.id.includes('stove') || obj.id.includes('espresso'))) {
        const elapsed = this._activeInteractions.get(obj.id);
        if (elapsed < 200) {
          ctx.fillStyle = `rgba(255, 255, 255, ${0.2 * (1 - elapsed / 200)})`;
          ctx.fillRect(pxX, pxY, w, h);
        }
      }

      // Spawn particles if object has them
      if (obj.particles && PARTICLE_DEFS[obj.particles]) {
        this._maybeSpawnParticles(obj.particles, pxX + w / 2, pxY);
      }
    }
  }

  // ── Characters ──
  renderCharacters(characters, debug = false) {
    if (!characters || characters.length === 0) return;
    const ctx = this.ctx;
    const now = performance.now();

    // Sort by py for depth ordering (lower = drawn on top)
    const sorted = [...characters].sort((a, b) => a.py - b.py);

    for (const char of sorted) {
      const px = char.px;
      // Idle bob: 1px vertical offset on ~800ms cycle (phase offset per character)
      const idleBob = char.action !== 'walking'
        ? (Math.sin(now * 0.008 + char.tx * 2) > 0 ? 1 : 0)
        : 0;
      const py = char.py + idleBob;
      const sprite = this.characterSprites?.get(char.spriteKey);

      // Bounce effect on interaction start (scale 1.1→1.0 over 100ms)
      let bounceScale = 1;
      if (char.action === 'interacting') {
        const elapsed = 2000 - char.interactTimer;
        if (elapsed >= 0 && elapsed < 100) {
          bounceScale = 1 + 0.1 * (1 - elapsed / 100);
        }
      }

      if (sprite) {
        if (char.facing === 'left' || bounceScale !== 1) {
          ctx.save();
          const cx = px + TILE_SIZE / 2;
          const cy = py + TILE_SIZE / 2;
          ctx.translate(cx, cy);
          if (bounceScale !== 1) ctx.scale(bounceScale, bounceScale);
          if (char.facing === 'left') ctx.scale(-1, 1);
          ctx.drawImage(sprite, -TILE_SIZE / 2, -TILE_SIZE / 2, TILE_SIZE, TILE_SIZE);
          ctx.restore();
        } else {
          ctx.drawImage(sprite, px, py, TILE_SIZE, TILE_SIZE);
        }
      } else {
        // Fallback: simple character shape
        const cx = px + TILE_SIZE / 2;

        // Body
        ctx.fillStyle = char.colors?.outfit || '#888888';
        ctx.fillRect(cx - 3, py + 6, 6, 8);

        // Head
        ctx.fillStyle = char.colors?.body || '#ddccbb';
        ctx.beginPath();
        ctx.arc(cx, py + 4, 3, 0, Math.PI * 2);
        ctx.fill();

        // Hair
        ctx.fillStyle = char.colors?.hair || '#443322';
        ctx.beginPath();
        ctx.arc(cx, py + 3, 3, Math.PI, Math.PI * 2);
        ctx.fill();
      }

      // Object-specific interaction particles
      if (char.action === 'interacting') {
        const particleType = getInteractParticleType(char);
        this._maybeSpawnParticles(particleType, px + TILE_SIZE / 2, py + TILE_SIZE / 2);
      }
    }
  }

  // ── Character labels on text overlay (mood emoji + names) ──
  renderCharacterLabels(characters, debug = false) {
    if (!characters || characters.length === 0) return;
    const ctx = this.textCtx;
    const s = this.textScale;

    for (const char of characters) {
      const px = char.px * s;
      const py = char.py * s;
      const tileS = TILE_SIZE * s;

      // Mood emoji above character
      if (char.moodEmoji) {
        ctx.font = `${Math.round(8 * s)}px serif`;
        ctx.textAlign = 'center';
        ctx.fillText(char.moodEmoji, px + tileS / 2, py - 1 * s);
      }

      // Name label below sprite
      const fontSize = Math.round(5 * s);
      ctx.font = `${fontSize}px monospace`;
      ctx.textAlign = 'center';
      const nameX = px + tileS / 2;
      const nameY = py + tileS + 6 * s;

      const label = debug ? `${char.name} [${char.action}]` : char.name;
      const metrics = ctx.measureText(label);
      const labelW = metrics.width + 3 * s;

      ctx.fillStyle = 'rgba(0,0,0,0.6)';
      ctx.fillRect(nameX - labelW / 2, nameY - 5 * s, labelW, 7 * s);

      ctx.fillStyle = '#ffffff';
      ctx.fillText(label, nameX, nameY);
    }
  }

  // ── Object labels (debug overlay) ──
  renderObjectLabels(objects) {
    const ctx = this.textCtx;
    const s = this.textScale;
    const fontSize = Math.round(5 * s);
    ctx.font = `${fontSize}px monospace`;
    ctx.textAlign = 'center';

    for (const obj of objects) {
      const tx = obj.position.tx;
      const ty = obj.position.ty;
      const pxX = (tx * TILE_SIZE + ((obj.position.tw || 1) * TILE_SIZE) / 2) * s;
      const pxY = (ty * TILE_SIZE - 2) * s;

      const text = `${obj.name} [${obj.state}]`;
      const metrics = ctx.measureText(text);
      const textW = metrics.width + 4 * s;

      ctx.fillStyle = 'rgba(0,0,0,0.7)';
      ctx.fillRect(pxX - textW / 2, pxY - 5 * s, textW, 7 * s);

      ctx.fillStyle = '#ffffff';
      ctx.fillText(text, pxX, pxY);

      // Timer bar under object
      if (obj.autoNextDuration !== null) {
        const remaining = obj.timeRemainingMs;
        const total = obj.autoNextDuration;
        const pct = (total - remaining) / total;
        const barW = ((obj.position.tw || 1) * TILE_SIZE - 4) * s;
        const barY = ((ty + (obj.position.th || 1)) * TILE_SIZE + 1) * s;
        const barX = (tx * TILE_SIZE + 2) * s;

        ctx.fillStyle = '#333333';
        ctx.fillRect(barX, barY, barW, 2 * s);
        ctx.fillStyle = pct > 0.85 ? '#d04020' : pct > 0.66 ? '#d0a020' : '#40a040';
        ctx.fillRect(barX, barY, barW * pct, 2 * s);
      }
    }
  }

  // ── Particles ──
  _maybeSpawnParticles(type, x, y) {
    const def = PARTICLE_DEFS[type];
    if (!def) return;
    const active = this.particles.filter(p => p.type === type).length;
    if (active >= def.count * 2) return;

    for (let i = 0; i < def.count; i++) {
      const color = def.colors
        ? def.colors[Math.floor(Math.random() * def.colors.length)]
        : def.color;

      let vx, vy;
      if (def.dir === 'down') {
        vx = (Math.random() - 0.5) * 0.5;
        vy = def.speed + Math.random() * 0.2;
      } else if (def.dir === 'radial') {
        const angle = Math.random() * Math.PI * 2;
        vx = Math.cos(angle) * def.speed;
        vy = Math.sin(angle) * def.speed;
      } else {
        vx = (Math.random() - 0.5) * 0.5;
        vy = -def.speed - Math.random() * 0.2;
      }

      this.particles.push({
        type,
        x: x + (Math.random() - 0.5) * 8,
        y: y,
        vx,
        vy,
        life: def.life * (0.7 + Math.random() * 0.6),
        maxLife: def.life,
        color,
        size: def.size,
        shape: def.shape || 'circle',
        wobble: def.wobble || false,
        phase: Math.random() * Math.PI * 2,
        age: 0,
      });
    }
  }

  renderParticles(dt) {
    const ctx = this.ctx;

    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= dt;
      if (p.life <= 0) {
        this.particles.splice(i, 1);
        continue;
      }

      p.x += p.vx;
      p.y += p.vy;
      p.age = (p.age || 0) + dt;

      const alpha = Math.max(0, p.life / p.maxLife);
      ctx.globalAlpha = alpha;
      ctx.fillStyle = p.color;

      // Sine wave wobble for steam/smoke
      const drawX = p.wobble
        ? p.x + Math.sin(p.age * 0.006 + (p.phase || 0)) * 1.5
        : p.x;

      if (p.shape === 'square') {
        ctx.fillRect(drawX - p.size / 2, p.y - p.size / 2, p.size, p.size);
      } else {
        ctx.beginPath();
        ctx.arc(drawX, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    ctx.globalAlpha = 1;
  }

  // ── Speech Bubble ──
  addSpeechBubble(tx, ty, text, durationMs = 3000) {
    this.speechBubbles.push({
      x: tx * TILE_SIZE + TILE_SIZE / 2,
      y: ty * TILE_SIZE - 10,
      text,
      life: durationMs,
      maxLife: durationMs,
    });
  }

  /** Add a speech bubble attached to a character (follows their position). */
  addCharacterSpeech(character, text, durationMs = 5000) {
    // Remove any existing bubble for this character
    this.speechBubbles = this.speechBubbles.filter(b => b.character !== character);

    // Truncate long text for the tiny canvas
    const maxLen = 60;
    const truncated = text.length > maxLen ? text.substring(0, maxLen - 1) + '\u2026' : text;

    this.speechBubbles.push({
      character,
      text: truncated,
      life: durationMs,
      maxLife: durationMs,
    });
  }

  setStatus(text) {
    this.statusText = text;
  }

  _wrapText(ctx, text, maxWidth) {
    const words = text.split(' ');
    const lines = [];
    let current = '';

    for (const word of words) {
      const test = current ? current + ' ' + word : word;
      if (ctx.measureText(test).width > maxWidth && current) {
        lines.push(current);
        current = word;
      } else {
        current = test;
      }
    }
    if (current) lines.push(current);
    return lines.length > 0 ? lines : [text];
  }

  renderSpeechBubbles(dt) {
    const ctx = this.textCtx;
    const s = this.textScale;
    const fontSize = Math.round(5 * s);
    ctx.font = `${fontSize}px monospace`;
    ctx.textAlign = 'center';

    for (let i = this.speechBubbles.length - 1; i >= 0; i--) {
      const b = this.speechBubbles[i];
      b.life -= dt;
      if (b.life <= 0) {
        this.speechBubbles.splice(i, 1);
        continue;
      }

      // Calculate anchor position (native coords scaled to text canvas)
      let anchorX, anchorY;
      if (b.character) {
        anchorX = (b.character.px + TILE_SIZE / 2) * s;
        anchorY = (b.character.py - 10) * s;
      } else {
        anchorX = b.x * s;
        anchorY = b.y * s;
      }

      const alpha = Math.min(1, b.life / 500);
      ctx.globalAlpha = alpha;

      // Word wrap
      const maxBubbleW = 100 * s;
      const lines = this._wrapText(ctx, b.text, maxBubbleW - 8 * s);
      const lineH = 7 * s;
      const padX = 4 * s;
      const padY = 3 * s;

      let maxLineW = 0;
      for (const line of lines) {
        const w = ctx.measureText(line).width;
        if (w > maxLineW) maxLineW = w;
      }

      const bw = maxLineW + padX * 2;
      const bh = lines.length * lineH + padY * 2;
      let bx = anchorX - bw / 2;
      const by = anchorY - bh;

      // Clamp to canvas bounds
      bx = Math.max(s, Math.min(bx, this.textCanvas.width - bw - s));

      // Background
      ctx.fillStyle = '#ffffff';
      ctx.beginPath();
      ctx.roundRect(bx, by, bw, bh, 3 * s);
      ctx.fill();

      // Tail
      const tailX = Math.max(bx + 4 * s, Math.min(anchorX, bx + bw - 4 * s));
      ctx.beginPath();
      ctx.moveTo(tailX - 3 * s, by + bh);
      ctx.lineTo(tailX, by + bh + 4 * s);
      ctx.lineTo(tailX + 3 * s, by + bh);
      ctx.fill();

      // Text lines
      ctx.fillStyle = '#222222';
      for (let l = 0; l < lines.length; l++) {
        ctx.fillText(lines[l], bx + bw / 2, by + padY + (l + 1) * lineH - s);
      }
    }

    ctx.globalAlpha = 1;
  }

  // ── Status Bar ──
  renderStatusBar() {
    if (!this.statusText) return;

    const ctx = this.textCtx;
    const s = this.textScale;
    const tw = this.textCanvas.width;
    const th = this.textCanvas.height;
    const barH = 12 * s;
    const y = th - barH;

    ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
    ctx.fillRect(0, y, tw, barH);

    const fontSize = Math.round(5 * s);
    ctx.font = `${fontSize}px monospace`;
    ctx.fillStyle = '#d0ccc4';
    ctx.textAlign = 'center';

    // Truncate if too wide
    let text = this.statusText;
    while (ctx.measureText(text).width > tw - 8 * s && text.length > 10) {
      text = text.substring(0, text.length - 4) + '\u2026';
    }

    ctx.fillText(text, tw / 2, y + 8 * s);
  }

  // ── Emoji Float ──
  addEmojiFloat(tx, ty, emoji) {
    this.emojiFloats.push({
      x: tx * TILE_SIZE + TILE_SIZE / 2,
      y: ty * TILE_SIZE,
      emoji,
      life: 1500,
      maxLife: 1500,
    });
  }

  renderEmojiFloats(dt) {
    const ctx = this.textCtx;
    const s = this.textScale;
    ctx.font = `${Math.round(12 * s)}px serif`;
    ctx.textAlign = 'center';

    for (let i = this.emojiFloats.length - 1; i >= 0; i--) {
      const e = this.emojiFloats[i];
      e.life -= dt;
      if (e.life <= 0) {
        this.emojiFloats.splice(i, 1);
        continue;
      }

      const progress = 1 - e.life / e.maxLife;
      const alpha = 1 - progress;
      const yOff = -progress * 20;

      ctx.globalAlpha = alpha;
      ctx.fillText(e.emoji, e.x * s, (e.y + yOff) * s);
    }

    ctx.globalAlpha = 1;
  }

  // ── Highlight a tile (for hover/click feedback) ──
  highlightTile(tx, ty, color = 'rgba(255,255,255,0.25)') {
    this.ctx.fillStyle = color;
    this.ctx.fillRect(tx * TILE_SIZE, ty * TILE_SIZE, TILE_SIZE, TILE_SIZE);
  }

  // ── Day/Night Cycle ──

  _initStars() {
    this._stars = [];
    for (let row = 0; row < MAP_ROWS; row++) {
      for (let col = 0; col < MAP_COLS; col++) {
        const tile = MAP[row][col];
        if (tile === T.WALL || tile === T.DOOR) {
          const count = 1 + Math.floor(Math.random() * 2);
          for (let i = 0; i < count; i++) {
            this._stars.push({
              x: col * TILE_SIZE + Math.random() * TILE_SIZE,
              y: row * TILE_SIZE + Math.random() * TILE_SIZE,
              phase: Math.random() * Math.PI * 2,
              size: 0.5 + Math.random() * 0.8,
            });
          }
        }
      }
    }
  }

  _initWaterTiles() {
    this._waterTiles = [];
    for (let row = 0; row < MAP_ROWS; row++) {
      for (let col = 0; col < MAP_COLS; col++) {
        if (false) { // no water tiles in café
          this._waterTiles.push({
            x: col * TILE_SIZE,
            y: row * TILE_SIZE,
            phase: (row * MAP_COLS + col) * 0.7,
          });
        }
      }
    }
  }

  _initWindowTiles() {
    this._windowTiles = [];
    for (let row = 0; row < MAP_ROWS; row++) {
      for (let col = 0; col < MAP_COLS; col++) {
        if (MAP[row][col] === T.FLOOR_WOOD || MAP[row][col] === T.FLOOR_TILE) {
          const neighbors = [
            [row - 1, col], [row + 1, col], [row, col - 1], [row, col + 1],
          ];
          const hasWall = neighbors.some(([r, c]) =>
            r >= 0 && r < MAP_ROWS && c >= 0 && c < MAP_COLS && MAP[r][c] === T.WALL
          );
          if (hasWall) {
            this._windowTiles.push({ x: col * TILE_SIZE, y: row * TILE_SIZE });
          }
        }
      }
    }
  }

  _initLanternPositions() {
    this._lanternPositions = [];
    for (const prop of PROPS) {
      if (prop.type === 'lantern') {
        this._lanternPositions.push({
          cx: prop.tx * TILE_SIZE + TILE_SIZE / 2,
          cy: prop.ty * TILE_SIZE + TILE_SIZE / 2,
        });
      }
    }
  }

  _getDayNightState(minuteOfDay) {
    const m = minuteOfDay;
    const TRANS = 30;
    const half = TRANS / 2;

    const NIGHT   = [0, 0, 50, 0.3];
    const GOLDEN  = [255, 160, 40, 0.08];
    const MORNING = [255, 200, 50, 0.1];
    const DAY     = [0, 0, 0, 0];
    const EVENING = [255, 100, 0, 0.15];

    function lerp4(a, b, t) {
      return [
        a[0] + (b[0] - a[0]) * t,
        a[1] + (b[1] - a[1]) * t,
        a[2] + (b[2] - a[2]) * t,
        a[3] + (b[3] - a[3]) * t,
      ];
    }

    function lerpN(a, b, t) { return a + (b - a) * t; }

    // Pre-dawn golden hour at 5am (300), sunrise at 6am (360)
    if (m < 300 - half) return { tint: NIGHT, nightFactor: 1 };
    if (m < 300 + half) {
      const t = (m - (300 - half)) / TRANS;
      return { tint: lerp4(NIGHT, GOLDEN, t), nightFactor: lerpN(1, 0.15, t) };
    }
    if (m < 360 - half) return { tint: GOLDEN, nightFactor: 0.15 };
    if (m < 360 + half) {
      const t = (m - (360 - half)) / TRANS;
      return { tint: lerp4(GOLDEN, MORNING, t), nightFactor: lerpN(0.15, 0, t) };
    }
    // Morning (6-10am)
    if (m < 600 - half) return { tint: MORNING, nightFactor: 0 };
    if (m < 600 + half) {
      const t = (m - (600 - half)) / TRANS;
      return { tint: lerp4(MORNING, DAY, t), nightFactor: 0 };
    }
    // Day (10am-5pm)
    if (m < 1020 - half) return { tint: DAY, nightFactor: 0 };
    if (m < 1020 + half) {
      const t = (m - (1020 - half)) / TRANS;
      return { tint: lerp4(DAY, EVENING, t), nightFactor: 0 };
    }
    // Evening (5-7pm)
    if (m < 1140 - half) return { tint: EVENING, nightFactor: 0 };
    // Sunset golden hour at 7pm (1140), night at 8pm (1200)
    if (m < 1140 + half) {
      const t = (m - (1140 - half)) / TRANS;
      return { tint: lerp4(EVENING, GOLDEN, t), nightFactor: lerpN(0, 0.15, t) };
    }
    if (m < 1200 - half) return { tint: GOLDEN, nightFactor: 0.15 };
    if (m < 1200 + half) {
      const t = (m - (1200 - half)) / TRANS;
      return { tint: lerp4(GOLDEN, NIGHT, t), nightFactor: lerpN(0.15, 1, t) };
    }
    return { tint: NIGHT, nightFactor: 1 };
  }

  renderDayNightCycle(minuteOfDay, now) {
    const { tint, nightFactor } = this._getDayNightState(minuteOfDay);
    const ctx = this.ctx;

    // Tint overlay — one fillRect per frame
    if (tint[3] > 0) {
      ctx.fillStyle = `rgba(${tint[0] | 0}, ${tint[1] | 0}, ${tint[2] | 0}, ${tint[3]})`;
      ctx.fillRect(0, 0, MAP_W, MAP_H);
    }

    // Window glow — warm amber rectangles on interior tiles at night
    if (nightFactor > 0.1) {
      if (!this._windowTiles) this._initWindowTiles();
      ctx.fillStyle = '#f0d888';
      ctx.globalAlpha = 0.15 + nightFactor * 0.1;
      for (const tile of this._windowTiles) {
        ctx.fillRect(tile.x, tile.y, TILE_SIZE, TILE_SIZE);
      }
      ctx.globalAlpha = 1;
    }

    // Lantern glow — radial gradient circles at lantern positions
    if (nightFactor > 0.1) {
      if (!this._lanternPositions) this._initLanternPositions();
      const glowAlpha = 0.3 + nightFactor * 0.2;
      const radius = TILE_SIZE * 2;

      for (const lantern of this._lanternPositions) {
        const gradient = ctx.createRadialGradient(
          lantern.cx, lantern.cy, 0,
          lantern.cx, lantern.cy, radius
        );
        gradient.addColorStop(0, `rgba(240, 216, 136, ${glowAlpha})`);
        gradient.addColorStop(1, 'rgba(240, 216, 136, 0)');
        ctx.fillStyle = gradient;
        ctx.fillRect(
          lantern.cx - radius, lantern.cy - radius,
          radius * 2, radius * 2
        );
      }
    }

    // Stars — twinkling white dots on WALL/DOOR tiles during night
    if (nightFactor > 0) {
      if (!this._stars) this._initStars();
      ctx.fillStyle = '#ffffff';
      for (const star of this._stars) {
        const twinkle = 0.3 + 0.7 * (0.5 + 0.5 * Math.sin(now * 0.003 + star.phase));
        ctx.globalAlpha = nightFactor * twinkle;
        ctx.fillRect(star.x - star.size / 2, star.y - star.size / 2, star.size, star.size);
      }
      ctx.globalAlpha = 1;
    }
  }

  // ── Pond Ripple ──
  renderPondRipple(now) {
    if (!this._waterTiles) this._initWaterTiles();
    const ctx = this.ctx;
    for (const tile of this._waterTiles) {
      const shimmer = 0.5 + 0.5 * Math.sin(now * 0.002 + tile.phase);
      ctx.fillStyle = '#ffffff';
      ctx.globalAlpha = shimmer * 0.1;
      ctx.fillRect(tile.x, tile.y, TILE_SIZE, TILE_SIZE);
    }
    ctx.globalAlpha = 1;
  }

  // ── Ambient Particles (fireflies, leaves) ──
  _updateAmbientParticles(dt, minuteOfDay) {
    const isNight = minuteOfDay >= 1200 || minuteOfDay < 360;

    // Fireflies — night only, up to 6
    if (isNight) {
      const fireflyCount = this._ambientParticles.filter(p => p.type === 'firefly').length;
      if (fireflyCount < 6) {
        this._ambientParticles.push({
          type: 'firefly',
          x: Math.random() * MAP_W,
          y: MAP_H * 0.2 + Math.random() * MAP_H * 0.6,
          vx: (Math.random() - 0.5) * 0.02,
          vy: (Math.random() - 0.5) * 0.02,
          dirTimer: 1000 + Math.random() * 2000,
          phase: Math.random() * Math.PI * 2,
          size: 1 + Math.random() * 0.5,
          life: 8000 + Math.random() * 12000,
        });
      }
    }

    // Leaf — one every 15-30 seconds
    this._leafTimer -= dt;
    if (this._leafTimer <= 0) {
      this._leafTimer = 15000 + Math.random() * 15000;
      const hasLeaf = this._ambientParticles.some(p => p.type === 'leaf');
      if (!hasLeaf) {
        this._ambientParticles.push({
          type: 'leaf',
          x: -4,
          y: Math.random() * MAP_H * 0.3,
          vx: 0.015 + Math.random() * 0.01,
          vy: 0.01 + Math.random() * 0.008,
          rotation: Math.random() * Math.PI,
          rotSpeed: (Math.random() - 0.5) * 0.002,
          life: 30000,
          color: Math.random() > 0.5 ? '#5a7a3a' : '#7a5a2a',
        });
      }
    }

    // Update all ambient particles
    for (let i = this._ambientParticles.length - 1; i >= 0; i--) {
      const p = this._ambientParticles[i];
      p.life -= dt;

      if (p.type === 'firefly') {
        if (!isNight) p.life = Math.min(p.life, 500); // fade out at dawn
        p.dirTimer -= dt;
        if (p.dirTimer <= 0) {
          p.vx = (Math.random() - 0.5) * 0.02;
          p.vy = (Math.random() - 0.5) * 0.02;
          p.dirTimer = 1000 + Math.random() * 2000;
        }
        if (p.x < 10 || p.x > MAP_W - 10) p.vx = -p.vx;
        if (p.y < 10 || p.y > MAP_H - 20) p.vy = -p.vy;
      }

      p.x += p.vx * dt;
      p.y += p.vy * dt;
      if (p.rotation !== undefined) p.rotation += p.rotSpeed * dt;

      if (p.life <= 0 || p.x > MAP_W + 10 || p.y > MAP_H + 10) {
        this._ambientParticles.splice(i, 1);
      }
    }
  }

  renderAmbientParticles(now) {
    const ctx = this.ctx;

    for (const p of this._ambientParticles) {
      if (p.type === 'firefly') {
        const glow = 0.4 + 0.6 * (0.5 + 0.5 * Math.sin(now * 0.004 + p.phase));
        const fade = Math.min(1, p.life / 500);
        ctx.globalAlpha = glow * fade;
        ctx.fillStyle = '#aadd44';
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
        // Glow halo
        ctx.globalAlpha = glow * fade * 0.25;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size * 3, 0, Math.PI * 2);
        ctx.fill();
      } else if (p.type === 'leaf') {
        ctx.globalAlpha = 0.7;
        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate(p.rotation);
        ctx.fillStyle = p.color;
        ctx.fillRect(-1.5, -1, 3, 2);
        ctx.restore();
      }
    }

    ctx.globalAlpha = 1;
  }

  // ── Full render frame ──
  startLoop(getObjects, getCharacters, options = {}) {
    this._lastTime = performance.now();

    const frame = (now) => {
      const dt = Math.min(now - this._lastTime, 100);
      this._lastTime = now;

      const objects = getObjects();
      const characters = getCharacters ? getCharacters() : null;
      const showDebug = options.showDebug && options.showDebug();

      // Build active interactions map for object flash effects
      this._activeInteractions = null;
      if (characters) {
        for (const char of characters) {
          if (char.action === 'interacting' && char.targetObjectId) {
            if (!this._activeInteractions) this._activeInteractions = new Map();
            this._activeInteractions.set(char.targetObjectId, 2000 - char.interactTimer);
          }
        }
      }

      // ── Main canvas (pixel art at native 768×1152 resolution) ──
      // Fill with solid background to prevent transparency bleed-through
      this.ctx.fillStyle = '#1a1a2e'; // café night background
      this.ctx.fillRect(0, 0, MAP_W, MAP_H);

      // Layer 1: tilemap
      this.renderTilemap();

      // Layer 1.5: pond ripple (water tile oscillation)
      this.renderPondRipple(now);

      // Layer 2: objects
      this.renderObjects(objects);

      // Layer 3: characters (sprites only, labels on text canvas)
      if (characters) {
        this.renderCharacters(characters);
      }

      // Layer 4: particles
      this.renderParticles(dt);

      // Layer 5: day/night cycle tint + stars
      if (options.getSimClock) {
        const clock = options.getSimClock();
        this.renderDayNightCycle(clock.minuteOfDay, now);
        this._updateAmbientParticles(dt, clock.minuteOfDay);
      }

      // Layer 5.5: ambient particles (fireflies glow through night tint, leaves)
      this.renderAmbientParticles(now);

      // ── Text overlay canvas (high-res for crisp text/emoji) ──
      this.textCtx.clearRect(0, 0, this.textCanvas.width, this.textCanvas.height);

      // Character labels (mood emoji + names)
      if (characters) {
        this.renderCharacterLabels(characters, showDebug);
      }

      // Emoji floats
      this.renderEmojiFloats(dt);

      // Speech bubbles
      this.renderSpeechBubbles(dt);

      // Status bar
      this.renderStatusBar();

      // Debug object labels
      if (showDebug) {
        this.renderObjectLabels(objects);
      }

      // Custom render callback
      if (this._renderCallback) {
        this._renderCallback(this.ctx, dt);
      }

      this._rafId = requestAnimationFrame(frame);
    };

    this._rafId = requestAnimationFrame(frame);
  }

  stopLoop() {
    if (this._rafId) {
      cancelAnimationFrame(this._rafId);
      this._rafId = null;
    }
  }

  onRender(callback) {
    this._renderCallback = callback;
  }
}

