/**
 * Café tilemap — two-floor cozy café scene
 * Upper: Nyx's apartment | Lower: Maple's café
 * Stacked vertically in the map array
 */

export const TILE_SIZE = 48;
export const MAP_COLS = 16;
export const MAP_ROWS = 24;  // 8 apartment + 2 separator + 14 café
export const MAP_W = MAP_COLS * TILE_SIZE;
export const MAP_H = MAP_ROWS * TILE_SIZE;

// ── Tile type IDs ──
export const T = {
  FLOOR_WOOD:    0,
  FLOOR_TILE:    1,
  WALL:          2,
  COUNTER:       3,
  WINDOW:        4,
  DOOR:          5,
  STAIRS:        6,
  GRASS:         7,
  FLOOR_CARPET:  8,
  WALL_TOP:      9,
  COUNTER_L:    10,
  COUNTER_R:    11,
  FLOOR_DARK:   12,
  SIDEWALK:     13,
};

// ── Fallback colors ──
export const TILE_COLORS = {
  [T.FLOOR_WOOD]:   '#c2956b',
  [T.FLOOR_TILE]:   '#d4c5a9',
  [T.WALL]:         '#5a4a3a',
  [T.COUNTER]:      '#8b6d4a',
  [T.WINDOW]:       '#87ceeb',
  [T.DOOR]:         '#6b4a2a',
  [T.STAIRS]:       '#9a8a6a',
  [T.GRASS]:        '#4a7c3f',
  [T.FLOOR_CARPET]: '#8b4040',
  [T.WALL_TOP]:     '#4a3a2a',
  [T.COUNTER_L]:    '#7b5d3a',
  [T.COUNTER_R]:    '#7b5d3a',
  [T.FLOOR_DARK]:   '#6b5030',
  [T.SIDEWALK]:     '#a09d98',
};

// ── Tile sprite paths ──
export const TILE_SPRITES = {
  [T.FLOOR_WOOD]:   'assets/cafe/tiles/floor_wood.png',
  [T.FLOOR_TILE]:   'assets/cafe/tiles/floor_tile.png',
  [T.WALL]:         'assets/cafe/tiles/wall_cafe.png',
  [T.COUNTER]:      'assets/cafe/tiles/counter.png',
  [T.WINDOW]:       'assets/cafe/tiles/window.png',
  [T.DOOR]:         'assets/cafe/tiles/door.png',
  [T.STAIRS]:       'assets/cafe/tiles/stairs.png',
  [T.GRASS]:        'assets/cafe/tiles/grass.png',
  [T.FLOOR_CARPET]: 'assets/cafe/tiles/floor_carpet.png',
  [T.WALL_TOP]:     'assets/cafe/tiles/wall_cafe_top.png',
  [T.COUNTER_L]:    'assets/cafe/tiles/counter_left.png',
  [T.COUNTER_R]:    'assets/cafe/tiles/counter_right.png',
  [T.FLOOR_DARK]:   'assets/cafe/tiles/floor_wood_dark.png',
  [T.SIDEWALK]:     'assets/cafe/tiles/sidewalk.png',
};

// Shorthand
const F = T.FLOOR_WOOD;
const I = T.FLOOR_TILE;  // tile floor
const W = T.WALL;
const C = T.COUNTER;
const N = T.WINDOW;
const D = T.DOOR;
const S = T.STAIRS;
const G = T.GRASS;
const R = T.FLOOR_CARPET;
const T2 = T.WALL_TOP;
const CL = T.COUNTER_L;
const CR = T.COUNTER_R;
const K = T.FLOOR_DARK;
const P = T.SIDEWALK;

// ── Map layout (24 rows × 16 cols) ──
// Rows 0-7: Nyx's apartment (upper floor)
// Rows 8-9: Floor separator / exterior wall
// Rows 10-23: Maple's café (ground floor)
export const MAP = [
  // ===== UPPER FLOOR — Nyx's Apartment =====
  // Row 0: Top wall
  [T2,T2,T2,T2,T2,T2,T2,T2,T2,T2,T2,T2,T2,T2,T2,T2],
  // Row 1: bedroom + kitchen wall
  [W, F, F, F, F, F, W, W, K, K, K, K, K, K, K, W],
  // Row 2: bed area + stove/fridge
  [W, F, F, F, F, F, W, N, K, K, K, K, K, K, K, W],
  // Row 3: desk/easel area + table
  [W, F, F, F, F, F, F, F, K, K, K, K, K, K, K, W],
  // Row 4: living area
  [W, F, F, F, F, F, F, F, K, K, K, K, K, K, K, W],
  // Row 5: living area — carpet rug zone under sofa/coffee table (cols 9-13)
  [W, F, F, F, F, F, F, F, F, R, R, R, R, R, F, W],

