// ═══════════════════════════════════════════════════════════
// World Definition — Café Objects
// ═══════════════════════════════════════════════════════════
//
// World tree: World → Sector → Arena → Object
// Each object is a JSON state machine definition.
// Times are in seconds (converted to ms by the engine).
// Positions use tile coordinates (tx, ty) for the 16×24 grid.
//
// GROUND FLOOR (rows 10-20): Maple's café
// UPPER FLOOR (rows 1-6): Nyx's apartment
// Separator (rows 7-9): exterior/stairs

// ── Sector layout ──
export const SECTORS = {
  cafe:      { name: 'Café',      tx: 8,  ty: 15 },
  apartment: { name: 'Apartment', tx: 8,  ty: 4  },
};

// ── World tree (for perception / AI context) ──
export const WORLD_TREE = {
  cafe: {
    name: 'Café',
    arenas: {
      counter: {
        name: 'Counter Area',
        objects: ['cafe_espresso', 'cafe_coffee_maker', 'cafe_display', 'cafe_register', 'cafe_sink'],
      },
      seating: {
        name: 'Seating Area',
        objects: ['cafe_book'],
      },
    },
  },
